import{c as o,Q as n,j as i,m as a}from"./chunks/framework.CdiUUa3G.js";const g=JSON.parse('{"title":"LEARN-link + /library backlog","description":"","frontmatter":{},"headers":[],"relativePath":"wip/learn-link-backlog.md","filePath":"wip/learn-link-backlog.md"}'),t={name:"wip/learn-link-backlog.md"};function s(r,e,l,c,d,h){return n(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="learn-link-library-backlog" tabindex="-1">LEARN-link + /library backlog <a class="header-anchor" href="#learn-link-library-backlog" aria-label="Permalink to &quot;LEARN-link + /library backlog&quot;">​</a></h1><p>This file is the rolling backlog for <strong>outbound LEARN-link stewardship and the public <code>/library</code> page</strong> that are not yet shipped. ADR-051 (&quot;Outbound learn-link stewardship&quot;) locks the data model, pipeline, and rendering rules; this list keeps the <strong>next-step ideas</strong> in one place so they don&#39;t get lost as scattered TODOs across the codebase.</p><p>Companion to <a href="./provenance-backlog"><code>provenance-backlog.md</code></a>, which covers the imagery side (ADR-047).</p><blockquote><p>Add new ideas here rather than as inline <code>// TODO</code>s. When an item ships, move its bullet into the relevant ADR (051 or a successor) and delete it here.</p></blockquote><hr><h2 id="cadence" tabindex="-1">Cadence <a class="header-anchor" href="#cadence" aria-label="Permalink to &quot;Cadence&quot;">​</a></h2><ul><li>[ ] <strong>Weekly link-check GH Action.</strong> Cron-triggered <code>npm run check-learn-links</code> that opens or updates a tracking issue when <code>intro</code> / <code>core</code> links go 4xx or 5xx. Diff report committed under <code>docs/provenance/link-checks/YYYY-MM-DD.md</code>. Until this lands, link-checking happens at refetch time only.</li><li>[ ] <strong>Per-locale staleness check on link labels.</strong> A linter that flags when <code>static/data/missions/&lt;dest&gt;/&lt;id&gt;.json</code> has gained a new English label but the locale overlay has not been retranslated. Surfaces in <code>validate-data</code>.</li><li>[ ] <strong>PR comment hook on link-provenance changes.</strong> On every PR that touches <code>static/data/link-provenance.json</code>, post the link-check diff as a PR comment so reviewers see &quot;1 redirect, 2 added, 1 replaced&quot; without opening the file.</li></ul><h2 id="source-diversity-follow-ups" tabindex="-1">Source diversity follow-ups <a class="header-anchor" href="#source-diversity-follow-ups" aria-label="Permalink to &quot;Source diversity follow-ups&quot;">​</a></h2><ul><li>[ ] <strong>Backfill Hindi-language ISRO links</strong> for Mangalyaan and the Chandrayaan family. ISRO publishes Hindi-language press notes; the audit did not find them because the link maps were English-only.</li><li>[ ] <strong>Backfill Russian-language Roscosmos links</strong> beyond the obvious <code>roscosmos.ru/22XXX/</code> mission pages — e.g. <code>tass.ru</code> cosmonautics archive, Lavochkin Association builder pages, Energia Russian-language iss-segment pages.</li><li>[ ] <strong>Backfill Chinese-language CNSA links</strong> for Chang&#39;e family + Tianwen-1. <code>cnsa.gov.cn</code> is bilingual but the URLs differ; the manifest currently records only the English variant for ease of authoring.</li><li>[ ] <strong>Educational publishers in non-US languages</strong> — TASS Cosmonautics encyclopedia, Xinhua space coverage, NHK Cosmos archives. None are agency primary sources but they fill the science-publisher tier in their own languages.</li></ul><h2 id="detection-regression" tabindex="-1">Detection / regression <a class="header-anchor" href="#detection-regression" aria-label="Permalink to &quot;Detection / regression&quot;">​</a></h2><ul><li>[ ] <strong>Sentry breadcrumb when a LEARN link returns 4xx in the wild.</strong> A client-side heads-up when a user clicks an outbound link the link-checker has not yet caught (since the checker is refetch-cadence, not real-time). Single <code>console.warn</code> + Sentry breadcrumb; no PII.</li><li>[ ] <strong>Playwright visual regression on <code>/library</code>.</strong> Snapshots of en-US, one CJK locale, and one RTL locale, sized for mobile + desktop. Fails when grouping or layout changes silently.</li><li>[ ] <strong>Type-level guarantee on i18n keys for <code>/library</code>.</strong> Today <code>library_*</code> keys are just strings; a new section without an i18n key compiles silently. A lint rule (or a test that walks <code>linkSourceId</code> outputs and asserts each maps to an <code>m.library_*</code> function) catches that drift.</li></ul><h2 id="authoring-ownership" tabindex="-1">Authoring + ownership <a class="header-anchor" href="#authoring-ownership" aria-label="Permalink to &quot;Authoring + ownership&quot;">​</a></h2><ul><li>[ ] <strong>CODEOWNERS entry.</strong> Require owner review on changes to <code>static/data/link-provenance.json</code>, <code>scripts/build-link-provenance.ts</code>, <code>scripts/check-learn-links.ts</code>, <code>static/data/source-logos.json</code>. Same pattern as the imagery side.</li><li>[ ] <strong>Authoring contract in PR template.</strong> Extend the existing checkbox: &quot;If this PR adds, edits, or removes an outbound LEARN link, did you re-run <code>npm run build-link-provenance</code> and <code>npm run check-learn-links</code>?&quot;</li><li>[ ] <strong><code>scripts/check-link-provenance-drift.ts</code>.</strong> Pre-push hook that runs <code>build-link-provenance --dry-run</code> and fails if <code>link-provenance.json</code> would change. Stops the case where someone hand-edits a <code>links[]</code> array without re-running the manifest builder.</li></ul><h2 id="public-surface" tabindex="-1">Public surface <a class="header-anchor" href="#public-surface" aria-label="Permalink to &quot;Public surface&quot;">​</a></h2><ul><li>[ ] <strong>Search / filter on <code>/library</code>.</strong> Filter by source, language, kind, tier, route. Useful once the manifest grows past ~1500 links; defer until that&#39;s a problem.</li><li>[ ] <strong>Per-source <code>?source=esa</code> deep links.</strong> Today the page uses anchor links. Adding query-param deep links makes individual source sections shareable.</li><li>[ ] <strong>Pagination / virtualisation</strong> — the page is plain HTML lists today. Revisit when render time crosses ~250 ms on the smallest target device.</li><li>[ ] <strong>JSON-LD <code>sameAs</code> block on entity pages</strong> for SEO discoverability of source diversity. A Tianwen-1 panel page links to <code>cnsa.gov.cn</code> and <code>en.wikipedia.org/wiki/Tianwen-1</code> — emit <code>&lt;script type=&quot;application/ld+json&quot;&gt;</code> with <code>sameAs</code> pointing at the operator portal so search engines see the primary-source signal.</li><li>[ ] <strong>Per-link &quot;report broken&quot; button</strong> that opens a pre-filled GH issue. Lower-friction than waiting for the checker to catch the break.</li></ul><h2 id="coverage-gaps" tabindex="-1">Coverage gaps <a class="header-anchor" href="#coverage-gaps" aria-label="Permalink to &quot;Coverage gaps&quot;">​</a></h2><ul><li>[ ] <strong>Backfill <code>last_verified</code> from per-host CDN headers</strong> instead of the HEAD probe timestamp. Some hosts (esa.int, jaxa.jp) ship <code>Last-Modified</code> headers that are more honest than &quot;we pinged it on date X&quot;.</li><li>[ ] <strong>Press kit ingestion.</strong> When a mission ships a press kit (PDF or microsite), record it as a <code>kind: &#39;mission-microsite&#39;</code> <code>core</code> link with the press-kit publication date as <code>last_verified</code>. Today press kits are ad-hoc.</li><li>[ ] <strong>Per-publisher rate-limit etiquette.</strong> Document each agency&#39;s preferred crawl rate in the link-checker. NASA hosts handle 10 req/s fine; agency CMSes (esa.int, isro.gov.in) prefer 1 req/s; smaller national agencies may want even less.</li></ul><h2 id="out-of-scope-intentional" tabindex="-1">Out of scope (intentional) <a class="header-anchor" href="#out-of-scope-intentional" aria-label="Permalink to &quot;Out of scope (intentional)&quot;">​</a></h2><ul><li><strong>Runtime LEARN-link rendering hops.</strong> ADR-016 still rules; the LEARN tab reads the manifest at view time but never live-checks a link.</li><li><strong>In-app preview of the destination page.</strong> Frame-busting and cross-origin policies make in-app previews unreliable; we keep the open-in-new-tab UX per ADR-051 rendering rules.</li><li><strong>Full archive of every page we link to.</strong> Wayback Machine handles that. We do not duplicate it.</li></ul><hr><p><em>Updated when ideas land or new ideas surface. Cite this file from PRs that defer LEARN-link work.</em></p>',21)])])}const p=o(t,[["render",s]]);export{g as __pageData,p as default};
